<!DOCTYPE html>
<html lang="el">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <meta name="description" content="L.D TRADING - Εμπόριο ενδυμάτων, υποδημάτων, δερμάτινων ειδών και αξεσουάρ στην Αττική." />
  <title>L.D TRADING | Εμπόριο Ενδυμάτων & Αξεσουάρ</title>
  <style>
    :root {
      --bg-deep: #0f0f18;
      --bg-accent: #1a1a2e;
      --primary: #c9a227;
      --primary-light: #f3d779;
      --text: #f5f5f7;
      --text-muted: #b0b0c0;
      --glass: rgba(255, 255, 255, 0.07);
      --glass-border: rgba(255, 255, 255, 0.12);
      --shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.45);
      --radius: 1.5rem;
      --transition: 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);
    }

    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    html {
      scroll-behavior: smooth;
    }

    body {
      font-family: "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background: var(--bg-deep);
      color: var(--text);
      line-height: 1.6;
      overflow-x: hidden;
    }

    /* Background animated gradient */
    body::before {
      content: "";
      position: fixed;
      inset: 0;
      z-index: -2;
      background: linear-gradient(135deg, #0f0f18 0%, #1a1a2e 40%, #2d1b2e 100%);
      background-size: 300% 300%;
      animation: gradientMove 18s ease infinite;
    }

    body::after {
      content: "";
      position: fixed;
      inset: 0;
      z-index: -1;
      background:
        radial-gradient(circle at 10% 20%, rgba(201, 162, 39, 0.12) 0%, transparent 35%),
        radial-gradient(circle at 90% 80%, rgba(147, 112, 219, 0.12) 0%, transparent 35%);
      pointer-events: none;
    }

    @keyframes gradientMove {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }

    /* Header */
    header {
      position: fixed;
      top: 0;
      left: 0;
      width: 100%;
      z-index: 1000;
      background: rgba(15, 15, 24, 0.65);
      backdrop-filter: blur(16px);
      -webkit-backdrop-filter: blur(16px);
      border-bottom: 1px solid var(--glass-border);
      transition: var(--transition);
    }

    .nav-container {
      max-width: 1200px;
      margin: 0 auto;
      padding: 1rem 2rem;
      display: flex;
      align-items: center;
      justify-content: space-between;
    }

    .logo {
      font-size: 1.35rem;
      font-weight: 800;
      letter-spacing: 1px;
      color: var(--text);
      text-decoration: none;
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }

    .logo span {
      color: var(--primary);
    }

    .logo small {
      display: block;
      font-size: 0.6rem;
      font-weight: 500;
      color: var(--text-muted);
      letter-spacing: 2px;
      text-transform: uppercase;
    }

    nav {
      display: flex;
      align-items: center;
      gap: 2rem;
    }

    .nav-links {
      display: flex;
      list-style: none;
      gap: 2rem;
    }

    .nav-links a {
      color: var(--text-muted);
      text-decoration: none;
      font-weight: 500;
      font-size: 0.95rem;
      position: relative;
      transition: color 0.3s ease;
    }

    .nav-links a::after {
      content: "";
      position: absolute;
      bottom: -4px;
      left: 0;
      width: 0;
      height: 2px;
      background: var(--primary);
      transition: width 0.3s ease;
    }

    .nav-links a:hover {
      color: var(--text);
    }

    .nav-links a:hover::after {
      width: 100%;
    }

    .cta-header {
      background: linear-gradient(135deg, var(--primary), var(--primary-light));
      color: #15151f;
      padding: 0.6rem 1.3rem;
      border-radius: 2rem;
      font-weight: 700;
      text-decoration: none;
      transition: transform 0.3s ease, box-shadow 0.3s ease;
      border: none;
      cursor: pointer;
    }

    .cta-header:hover {
      transform: translateY(-2px);
      box-shadow: 0 10px 25px rgba(201, 162, 39, 0.35);
    }

    .menu-toggle {
      display: none;
      flex-direction: column;
      gap: 5px;
      background: none;
      border: none;
      cursor: pointer;
      padding: 0.5rem;
    }

    .menu-toggle span {
      display: block;
      width: 26px;
      height: 2px;
      background: var(--text);
      border-radius: 2px;
      transition: 0.3s ease;
    }

    /* Hero */
    .hero {
      min-height: 100vh;
      display: flex;
      align-items: center;
      justify-content: center;
      text-align: center;
      padding: 8rem 2rem 5rem;
      position: relative;
    }

    .hero-blob {
      position: absolute;
      border-radius: 50%;
      filter: blur(80px);
      opacity: 0.5;
      z-index: -1;
    }

    .blob-1 {
      width: 400px;
      height: 400px;
      background: rgba(201, 162, 39, 0.25);
      top: 10%;
      left: -100px;
      animation: float 7s ease-in-out infinite;
    }

    .blob-2 {
      width: 350px;
      height: 350px;
      background: rgba(147, 112, 219, 0.2);
      bottom: 10%;
      right: -80px;
      animation: float 9s ease-in-out infinite reverse;
    }

    @keyframes float {
      0%, 100% { transform: translateY(0); }
      50% { transform: translateY(-20px); }
    }

    .hero-content {
      max-width: 850px;
      animation: fadeInUp 1s ease forwards;
      opacity: 0;
    }

    .hero-content h1 {
      font-size: clamp(2.5rem, 6vw, 4.5rem);
      font-weight: 900;
      line-height: 1.1;
      margin-bottom: 1.5rem;
      background: linear-gradient(135deg, #ffffff 0%, var(--primary-light) 100%);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
    }

    .hero-content p {
      font-size: clamp(1rem, 2vw, 1.3rem);
      color: var(--text-muted);
      margin-bottom: 2.5rem;
      max-width: 700px;
      margin-left: auto;
      margin-right: auto;
    }

    .hero-buttons {
      display: flex;
      gap: 1rem;
      justify-content: center;
      flex-wrap: wrap;
    }

    .btn {
      display: inline-flex;
      align-items: center;
      gap: 0.5rem;
      padding: 0.95rem 2rem;
      border-radius: 2rem;
      font-weight: 700;
      font-size: 1rem;
      text-decoration: none;
      transition: var(--transition);
      border: none;
      cursor: pointer;
    }

    .btn-primary {
      background: linear-gradient(135deg, var(--primary), var(--primary-light));
      color: #15151f;
      box-shadow: 0 10px 30px rgba(201, 162, 39, 0.3);
    }

    .btn-primary:hover {
      transform: translateY(-3px) scale(1.02);
      box-shadow: 0 15px 40px rgba(201, 162, 39, 0.45);
    }

    .btn-secondary {
      background: var(--glass);
      color: var(--text);
      border: 1px solid var(--glass-border);
      backdrop-filter: blur(8px);
    }

    .btn-secondary:hover {
      background: rgba(255, 255, 255, 0.12);
      transform: translateY(-3px);
    }

    /* Sections */
    section {
      padding: 6rem 2rem;
      max-width: 1200px;
      margin: 0 auto;
    }

    .section-header {
      text-align: center;
      margin-bottom: 4rem;
      max-width: 700px;
      margin-left: auto;
      margin-right: auto;
    }

    .section-header h2 {
      font-size: clamp(2rem, 4vw, 2.8rem);
      font-weight: 800;
      margin-bottom: 1rem;
      color: var(--text);
    }

    .section-header p {
      color: var(--text-muted);
      font-size: 1.1rem;
    }

    .section-header h2 span {
      color: var(--primary);
    }

    /* Cards grid */
    .cards-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
      gap: 2rem;
    }

    .card {
      background: var(--glass);
      border: 1px solid var(--glass-border);
      border-radius: var(--radius);
      padding: 2.5rem 2rem;
      text-align: center;
      backdrop-filter: blur(14px);
      -webkit-backdrop-filter: blur(14px);
      box-shadow: var(--shadow);
      transition: var(--transition);
      position: relative;
      overflow: hidden;
    }

    .card::before {
      content: "";
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 4px;
      background: linear-gradient(90deg, var(--primary), var(--primary-light));
      transform: scaleX(0);
      transform-origin: left;
      transition: transform 0.4s ease;
    }

    .card:hover {
      transform: translateY(-10px);
      border-color: rgba(201, 162, 39, 0.4);
      box-shadow: 0 30px 60px rgba(0, 0, 0, 0.5);
    }

    .card:hover::before {
      transform: scaleX(1);
    }

    .card-icon {
      width: 70px;
      height: 70px;
      margin: 0 auto 1.5rem;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      background: linear-gradient(135deg, rgba(201, 162, 39, 0.2), rgba(147, 112, 219, 0.2));
      border: 1px solid var(--glass-border);
    }

    .card-icon svg {
      width: 34px;
      height: 34px;
      stroke: var(--primary-light);
      fill: none;
      stroke-width: 2;
      stroke-linecap: round;
      stroke-linejoin: round;
    }

    .card h3 {
      font-size: 1.3rem;
      margin-bottom: 0.75rem;
      color: var(--text);
    }

    .card p {
      color: var(--text-muted);
      font-size: 0.95rem;
    }

    /* About */
    .about-wrapper {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 3rem;
      align-items: center;
    }

    .about-text {
      background: var(--glass);
      border: 1px solid var(--glass-border);
      border-radius: var(--radius);
      padding: 3rem;
      backdrop-filter: blur(14px);
      box-shadow: var(--shadow);
    }

    .about-text h3 {
      font-size: 2rem;
      margin-bottom: 1.5rem;
      color: var(--text);
    }

    .about-text h3 span {
      color: var(--primary);
    }

    .about-text p {
      color: var(--text-muted);
      margin-bottom: 1.25rem;
    }

    .about-visual {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1.5rem;
    }

    .stat {
      background: var(--glass);
      border: 1px solid var(--glass-border);
      border-radius: var(--radius);
      padding: 2rem;
      text-align: center;
      backdrop-filter: blur(12px);
      transition: var(--transition);
    }

    .stat:hover {
      transform: translateY(-5px);
      border-color: rgba(201, 162, 39, 0.35);
    }

    .stat strong {
      display: block;
      font-size: 2.2rem;
      color: var(--primary-light);
      margin-bottom: 0.5rem;
    }

    .stat span {
      color: var(--text-muted);
      font-size: 0.9rem;
    }

    /* Contact */
    .contact-wrapper {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 3rem;
      background: var(--glass);
      border: 1px solid var(--glass-border);
      border-radius: var(--radius);
      padding: 3rem;
      backdrop-filter: blur(16px);
      box-shadow: var(--shadow);
    }

    .contact-info h3 {
      font-size: 1.8rem;
      margin-bottom: 1rem;
    }

    .contact-info p {
      color: var(--text-muted);
      margin-bottom: 2rem;
    }

    .contact-item {
      display: flex;
      align-items: center;
      gap: 1rem;
      margin-bottom: 1.25rem;
      color: var(--text-muted);
    }

    .contact-item svg {
      width: 22px;
      height: 22px;
      stroke: var(--primary-light);
      fill: none;
      stroke-width: 2;
      stroke-linecap: round;
      stroke-linejoin: round;
      flex-shrink: 0;
    }

    .contact-item a {
      color: var(--text);
      text-decoration: none;
      font-weight: 600;
      transition: color 0.3s ease;
    }

    .contact-item a:hover {
      color: var(--primary-light);
    }

    .contact-form {
      display: flex;
      flex-direction: column;
      gap: 1.25rem;
    }

    .form-group {
      position: relative;
    }

    .form-group input,
    .form-group textarea {
      width: 100%;
      padding: 1rem 1.2rem;
      border-radius: 1rem;
      border: 1px solid var(--glass-border);
      background: rgba(0, 0, 0, 0.25);
      color: var(--text);
      font-size: 1rem;
      outline: none;
      transition: border-color 0.3s ease, box-shadow 0.3s ease;
      font-family: inherit;
    }

    .form-group input::placeholder,
    .form-group textarea::placeholder {
      color: #8888a0;
    }

    .form-group input:focus,
    .form-group textarea:focus {
      border-color: var(--primary);
      box-shadow: 0 0 0 3px rgba(201, 162, 39, 0.15);
    }

    .form-group textarea {
      min-height: 140px;
      resize: vertical;
    }

    /* Footer */
    footer {
      text-align: center;
      padding: 2.5rem 2rem;
      color: var(--text-muted);
      font-size: 0.9rem;
      border-top: 1px solid var(--glass-border);
      background: rgba(0, 0, 0, 0.2);
    }

    footer strong {
      color: var(--primary-light);
    }

    /* Animations */
    @keyframes fadeInUp {
      from {
        opacity: 0;
        transform: translateY(30px);
      }
      to {
        opacity: 1;
        transform: translateY(0);
      }
    }

    .reveal {
      opacity: 0;
      transform: translateY(40px);
      transition: all 0.8s cubic-bezier(0.25, 0.46, 0.45, 0.94);
    }

    .reveal.active {
      opacity: 1;
      transform: translateY(0);
    }

    /* Responsive */
    @media (max-width: 900px) {
      .about-wrapper,
      .contact-wrapper {
        grid-template-columns: 1fr;
      }

      .about-visual {
        order: -1;
      }
    }

    @media (max-width: 768px) {
      .nav-links {
        position: fixed;
        top: 0;
        right: 0;
        height: 100vh;
        width: 70%;
        max-width: 300px;
        flex-direction: column;
        align-items: flex-start;
        padding: 6rem 2rem 2rem;
        background: rgba(15, 15, 24, 0.97);
        backdrop-filter: blur(20px);
        transform: translateX(100%);
        transition: transform 0.4s ease;
        gap: 1.5rem;
        border-left: 1px solid var(--glass-border);
      }

      .nav-links.open {
        transform: translateX(0);
      }

      .cta-header {
        display: none;
      }

      .menu-toggle {
        display: flex;
        z-index: 1100;
      }

      .menu-toggle.active span:nth-child(1) {
        transform: rotate(45deg) translate(5px, 5px);
      }

      .menu-toggle.active span:nth-child(2) {
        opacity: 0;
      }

      .menu-toggle.active span:nth-child(3) {
        transform: rotate(-45deg) translate(6px, -6px);
      }

      .hero {
        padding-top: 7rem;
      }
    }
  </style>
</head>
